SELECT [Sales Price Model Item].[Model Item No_], [Item].[Product Family], [Item].[Product Sex], Min([Sales Price Model Item].[Variable Code 02]) AS FromSize, Max([Sales Price Model Item].[Variable Code 02]) AS ToSize, Val([Sales Price Model Item].[Unit Price]) AS SalesPrice, [Item].[Trademark Code], [Item].Description, [Sales Price Model Item].[Variable Group 01], [Sales Price Model Item].[Variable Code 01], [Variable Code].Description, [Item].[Line Code], [Sales Price Model Item].[Sales Code], Str(Min(Val([Sales Price Model Item].[variable code 02]))) & "-" & Str(Max(Val([Sales Price Model Item].[variable code 02]))) AS SizeRange, [Item].[Season Code], [Item].[Sales_Purchase Status Code]
FROM Item INNER JOIN ([Sales Price Model Item] INNER JOIN [Variable Code] ON [Sales Price Model Item].[Variable Code 01] = [Variable Code].[Variable Code]) ON ([Item].[Constant Assortment Var_Grp_] = [Variable Code].[Variable Group]) AND ([Item].No_ = [Sales Price Model Item].[Model Item No_])
GROUP BY [Sales Price Model Item].[Model Item No_], [Item].[Product Family], [Item].[Product Sex], Val([Sales Price Model Item].[Unit Price]), [Item].[Trademark Code], [Item].Description, [Sales Price Model Item].[Variable Group 01], [Sales Price Model Item].[Variable Code 01], [Variable Code].Description, [Item].[Line Code], [Sales Price Model Item].[Sales Code], [Item].[Season Code], [Item].[Sales_Purchase Status Code]
HAVING ((([Item].[Trademark Code])=[marchio]) AND (([Sales Price Model Item].[Variable Code 01])<>"") AND (([Sales Price Model Item].[Sales Code])=[listinoPubblico]) AND (([Item].[Season Code])=[stagione]));

